const raw = $json.body ?? $json ?? {};

  const host = String(raw.src_ip ?? raw.host ?? raw.source_ip ??
  'unknown').trim();
  const action = String(raw.alert ?? raw.action ?? raw.signature ??
  raw.event ?? 'unknown_event').trim();

  const sev = Number(raw.severity ?? raw.alert_severity ?? 1);
  const severity = Number.isFinite(sev) ? Math.min(5, Math.max(1, sev)) : 1;

  let timestamp = new Date().toISOString();
  if (raw.timestamp) {
    const d = new Date(raw.timestamp);
    if (!Number.isNaN(d.getTime())) timestamp = d.toISOString();
  }

  return {
    json: {
      host,
      action,
      severity,
      timestamp,
      raw
    }
  };

const WINDOW_MS = 10 * 60 * 1000;
const now = Date.now();
const event = $json;
const store = $getWorkflowStaticData('global');
if (!store.eventsByHost) store.eventsByHost = {};
const host = event.host || 'unknown';
const prev = Array.isArray(store.eventsByHost[host]) ? store.eventsByHost[host] : [];
const alive = prev.filter((e) => Number.isFinite(e.ts) && now - e.ts <= WINDOW_MS);
alive.push({
  ts: now,
  timestamp: event.timestamp,
  action: event.action,
  severity: event.severity
});
store.eventsByHost[host] = alive;
const event_count = alive.length;
const severity_avg = alive.reduce((a, b) => a + Number(b.severity || 0), 0) / Math.max(1, event_count);
return {
  json: {
    host,
    latest_event: event,
    window_minutes: 10,
    event_count,
    severity_avg,
    events: alive.map(({ timestamp, action, severity }) => ({ timestamp, action, severity }))
  }
};

const agg = $node['Aggregate 10m'].json;
const data = $input.item.json;
const text = data?.content?.parts?.[0]?.text ?? data?.text ?? '';
let llm;
try {
  llm = JSON.parse(text);
} catch (e) {
  llm = { risk: 0.0, attack_stage: 'Unknown', confidence: 'low', reason: text || 'unparsed' };
}
const clamp = (v, lo, hi) => Math.min(hi, Math.max(lo, v));
const llm_risk = clamp(Number(llm.risk ?? 0), 0, 1);
const ids_component = clamp(Number(agg.severity_avg ?? 1) / 5, 0, 1);
const final_score = 0.6 * llm_risk + 0.4 * ids_component;
let decision = 'benign';
if (final_score >= 0.7) decision = 'potential_apt';
else if (final_score >= 0.3) decision = 'suspicious';
return {
  json: {
    workflow: 'BTLPY_APT_LLM_Correlation',
    host: agg.host,
    event_count: agg.event_count,
    events: agg.events,
    ids_severity_avg: agg.severity_avg,
    llm_risk,
    attack_stage: String(llm.attack_stage ?? 'Unknown'),
    confidence: String(llm.confidence ?? 'low'),
    reason: String(llm.reason ?? ''),
    final_score: Number(final_score.toFixed(4)),
    decision,
    ts: new Date().toISOString()
  }
};

const raw = String($env.TELEGRAM_CHAT_IDS ?? $env.TELEGRAM_CHAT_ID ?? '').trim();
const chatIds = raw.split(/[\s,]+/).map((s) => s.trim()).filter(Boolean);
const x = $json;
const text = [
  '🚨 Potential APT Activity',
  `Host: ${x.host}`,
  `Risk Score: ${x.final_score}`,
  `Stage: ${x.attack_stage}`,
  `Confidence: ${x.confidence}`,
  '',
  `Reason: ${x.reason}`
].join('\n');
if (!chatIds.length) return [];
return chatIds.map((chatId) => ({ json: { chatId, text } }));

